#!/usr/bin/env python3
"""Parse email files (.eml/.mbox) to extract boss communications."""

import argparse
import email
import mailbox
import sys
from email.header import decode_header
from pathlib import Path


def decode_str(s):
    """Decode email header string."""
    if s is None:
        return ""
    decoded = decode_header(s)
    parts = []
    for content, charset in decoded:
        if isinstance(content, bytes):
            parts.append(content.decode(charset or "utf-8", errors="replace"))
        else:
            parts.append(content)
    return " ".join(parts)


def extract_body(msg):
    """Extract text body from email message."""
    if msg.is_multipart():
        for part in msg.walk():
            ct = part.get_content_type()
            if ct == "text/plain":
                payload = part.get_payload(decode=True)
                charset = part.get_content_charset() or "utf-8"
                return payload.decode(charset, errors="replace")
    else:
        payload = msg.get_payload(decode=True)
        if payload:
            charset = msg.get_content_charset() or "utf-8"
            return payload.decode(charset, errors="replace")
    return ""


def parse_eml(file_path: str, target: str) -> list:
    """Parse a single .eml file."""
    with open(file_path, "rb") as f:
        msg = email.message_from_binary_file(f)

    sender = decode_str(msg.get("From", ""))
    if target.lower() not in sender.lower():
        return []

    return [{
        "from": sender,
        "to": decode_str(msg.get("To", "")),
        "subject": decode_str(msg.get("Subject", "")),
        "date": decode_str(msg.get("Date", "")),
        "body": extract_body(msg),
    }]


def parse_mbox(file_path: str, target: str) -> list:
    """Parse an mbox file."""
    mbox = mailbox.mbox(file_path)
    results = []
    for msg in mbox:
        sender = decode_str(msg.get("From", ""))
        if target.lower() in sender.lower():
            results.append({
                "from": sender,
                "to": decode_str(msg.get("To", "")),
                "subject": decode_str(msg.get("Subject", "")),
                "date": decode_str(msg.get("Date", "")),
                "body": extract_body(msg),
            })
    return results


def main():
    parser = argparse.ArgumentParser(description="Parse boss emails")
    parser.add_argument("--file", required=True, help="Path to .eml or .mbox file")
    parser.add_argument("--target", required=True, help="Boss name to filter by")
    parser.add_argument("--output", required=True, help="Output file path")
    args = parser.parse_args()

    path = Path(args.file)
    if not path.exists():
        print(f"Error: file not found: {path}", file=sys.stderr)
        sys.exit(1)

    if path.suffix == ".mbox":
        emails = parse_mbox(str(path), args.target)
    else:
        emails = parse_eml(str(path), args.target)

    with open(args.output, "w", encoding="utf-8") as f:
        f.write(f"# Emails from {args.target}\n\n")
        f.write(f"Total: {len(emails)} emails\n\n")
        for i, e in enumerate(emails, 1):
            f.write(f"---\n## Email {i}\n")
            f.write(f"- From: {e['from']}\n")
            f.write(f"- To: {e['to']}\n")
            f.write(f"- Subject: {e['subject']}\n")
            f.write(f"- Date: {e['date']}\n\n")
            f.write(f"{e['body']}\n\n")

    print(f"Parsed {len(emails)} emails from {args.target} → {args.output}")


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""
飞书浏览器抓取器（Playwright 方案）

复用本机 Chrome 登录态，无需任何 token，能访问你有权限的所有飞书内容。

支持：
  - 飞书文档（docx/docs）
  - 飞书知识库（wiki）
  - 飞书表格（sheets）→ 导出为 CSV
  - 飞书消息记录（指定群聊）

安装：
  pip install playwright
  playwright install chromium

用法：
  python3 feishu_browser.py --url "https://xxx.feishu.cn/wiki/xxx" --output out.txt
  python3 feishu_browser.py --url "https://xxx.feishu.cn/docx/xxx" --output out.txt
  python3 feishu_browser.py --chat "后端组" --target "张三" --limit 500 --output out.txt
  python3 feishu_browser.py --url "https://xxx.feishu.cn/sheets/xxx" --output out.csv
"""

from __future__ import annotations

import sys
import time
import json
import argparse
import platform
from pathlib import Path
from typing import Optional


def get_default_chrome_profile() -> str:
    """根据操作系统返回 Chrome 默认 Profile 路径"""
    system = platform.system()
    if system == "Darwin":
        return str(Path.home() / "Library/Application Support/Google/Chrome/Default")
    elif system == "Linux":
        return str(Path.home() / ".config/google-chrome/Default")
    elif system == "Windows":
        import os
        return str(Path(os.environ.get("LOCALAPPDATA", "")) / "Google/Chrome/User Data/Default")
    return str(Path.home() / ".config/google-chrome/Default")


def make_context(playwright, chrome_profile: Optional[str], headless: bool):
    """创建复用登录态的浏览器上下文"""
    profile = chrome_profile or get_default_chrome_profile()
    try:
        ctx = playwright.chromium.launch_persistent_context(
            user_data_dir=profile,
            headless=headless,
            args=[
                "--disable-blink-features=AutomationControlled",
                "--no-first-run",
                "--no-default-browser-check",
            ],
            ignore_default_args=["--enable-automation"],
            viewport={"width": 1280, "height": 900},
        )
        return ctx
    except Exception as e:
        print(f"⚠️  无法加载 Chrome Profile：{e}", file=sys.stderr)
        print(f"   尝试的路径：{profile}", file=sys.stderr)
        print("   请用 --chrome-profile 手动指定路径", file=sys.stderr)
        sys.exit(1)


def detect_page_type(url: str) -> str:
    """根据 URL 判断飞书页面类型"""
    if "/wiki/" in url:
        return "wiki"
    elif "/docx/" in url or "/docs/" in url:
        return "doc"
    elif "/sheets/" in url or "/spreadsheets/" in url:
        return "sheet"
    elif "/base/" in url:
        return "base"
    else:
        return "unknown"


def fetch_doc(page, url: str) -> str:
    """抓取飞书文档或 Wiki 的文本内容"""
    page.goto(url, wait_until="domcontentloaded", timeout=30000)

    # 等待编辑器加载（飞书文档渲染较慢）
    selectors = [
        ".docs-reader-content",
        ".lark-editor-content",
        "[data-block-type]",
        ".doc-render-core",
        ".wiki-content",
        ".node-doc-content",
    ]

    loaded = False
    for sel in selectors:
        try:
            page.wait_for_selector(sel, timeout=15000)
            loaded = True
            break
        except Exception:
            continue

    if not loaded:
        # 等待一段时间后直接提取 body 文本
        time.sleep(5)

    # 额外等待异步内容渲染
    time.sleep(2)

    # 尝试多个选择器提取正文
    for sel in selectors:
        try:
            el = page.query_selector(sel)
            if el:
                text = el.inner_text()
                if len(text.strip()) > 50:
                    return text.strip()
        except Exception:
            continue

    # fallback：提取整个 body
    text = page.inner_text("body")
    return text.strip()


